import{_ as e,o as l,c as t,ag as i}from"./chunks/framework.DtEl18Xn.js";const o="/getbiji-docs-v3/images/PLrdbG8g3oMEGYxJvxWcALYCnVB.png",r="/getbiji-docs-v3/images/ZwMsbIgp3oZAJLxlhztciQBwnmf.png",u=JSON.parse('{"title":"Get 笔记 Skill","description":"","frontmatter":{"title":"Get 笔记 Skill ","lastUpdated":"2026-03-14T15:00:40.349Z"},"headers":[],"relativePath":"get-笔记-skill-.md","filePath":"get-笔记-skill-.md"}'),n={name:"get-笔记-skill-.md"};function p(s,a,h,c,k,d){return l(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="get-笔记-skill-是什么-有什么用" tabindex="-1">Get 笔记 Skill 是什么，有什么用 <a class="header-anchor" href="#get-笔记-skill-是什么-有什么用" aria-label="Permalink to &quot;Get 笔记 Skill 是什么，有什么用&quot;">​</a></h1><p><img src="'+o+`" alt=""></p><div class="language-1 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">1</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请安装 Get笔记 技能，帮我记录和查找笔记。</span></span>
<span class="line"><span>技能地址：https://clawhub.ai/iswalle/getnote</span></span>
<span class="line"><span>API Key 获取：https://www.biji.com/openapi</span></span></code></pre></div><h1 id="日常使用问题和解决方案" tabindex="-1">日常使用问题和解决方案 <a class="header-anchor" href="#日常使用问题和解决方案" aria-label="Permalink to &quot;日常使用问题和解决方案&quot;">​</a></h1><h2 id="🐛-bug-类问题" tabindex="-1">🐛 Bug 类问题 <a class="header-anchor" href="#🐛-bug-类问题" aria-label="Permalink to &quot;🐛 Bug 类问题&quot;">​</a></h2><h3 id="_1-笔记删除后直接彻底删除-未进回收站" tabindex="-1">1. 笔记删除后直接彻底删除，未进回收站 <a class="header-anchor" href="#_1-笔记删除后直接彻底删除-未进回收站" aria-label="Permalink to &quot;1. 笔记删除后直接彻底删除，未进回收站&quot;">​</a></h3><p>让小龙虾将某条笔记删除到回收站，笔记会被彻底删除，回收站为空，存在严重误删风险。</p><p>小龙虾删除的所有笔记都会进入回收站，可以在Get 笔记 打开侧边栏，点回收站查看</p><p>也可以在回收站选择恢复或者彻底删除</p><h3 id="_2-nas-上安装-skill-失败-云服务器正常" tabindex="-1">2. NAS 上安装 Skill 失败，云服务器正常 <a class="header-anchor" href="#_2-nas-上安装-skill-失败-云服务器正常" aria-label="Permalink to &quot;2. NAS 上安装 Skill 失败，云服务器正常&quot;">​</a></h3><p>在 NAS 上安装 get 笔记技能无法成功，换到云服务器则可以正常安装。</p><p>出于安全，建议使用限制 Mac 设备或者购买云服务版，Get 笔记 Skill 本身不限制安装设备</p><h3 id="_3-技能装入-coze-后持续报-403" tabindex="-1">3. 技能装入 Coze 后持续报 403 <a class="header-anchor" href="#_3-技能装入-coze-后持续报-403" aria-label="Permalink to &quot;3. 技能装入 Coze 后持续报 403&quot;">​</a></h3><p>将 Skill 部署到扣子（Coze）平台后，调用一直返回 403 错误。</p><p>Coze 等相关平台配置建议参考 OpenAPI 开发文档调用相关 API</p><ol><li>打开：<a href="https://www.biji.com/openapi" target="_blank" rel="noreferrer">https://www.biji.com/openapi</a></li><li>点击“使用文档”Tab</li></ol><h3 id="_4-安装-配置后-api-返回-pong-或者-503-错误" tabindex="-1">4. 安装 / 配置后 API 返回 pong 或者 503 错误 <a class="header-anchor" href="#_4-安装-配置后-api-返回-pong-或者-503-错误" aria-label="Permalink to &quot;4. 安装 / 配置后 API 返回 pong 或者 503 错误&quot;">​</a></h3><p>已开通会员、新建 API Key 并填写 Client ID，仍报「API 权限不够」「返回都是 pong 或者 返回 503 错误」。</p><p>这种情况可能是小龙虾开启网络搜索用了错误的 API 配置，建议解决方案</p><ol><li>告诉小龙虾：请严格按照 Skill.md 进行 API 调用，详情参考“快速决策”部分</li><li>告诉小龙虾卸载“Get 笔记”Skill，然后重新安装：帮我安装 Get笔记 skill，地址是 <a href="./https%3A%2F%2Fraw.githubusercontent.com%2Fiswalle%2Fgetnote-openclaw%2Fmain%2FSKILL.html">https://raw.githubusercontent.com/iswalle/getnote-openclaw/main/SKILL.md</a></li></ol><h2 id="💡-日常使用问题" tabindex="-1">💡 日常使用问题 <a class="header-anchor" href="#💡-日常使用问题" aria-label="Permalink to &quot;💡 日常使用问题&quot;">​</a></h2><h3 id="_1-安装-配置流程不会操作-手机能用吗-要在电脑上操作" tabindex="-1">1. 安装/配置流程不会操作，手机能用吗？要在电脑上操作？ <a class="header-anchor" href="#_1-安装-配置流程不会操作-手机能用吗-要在电脑上操作" aria-label="Permalink to &quot;1. 安装/配置流程不会操作，手机能用吗？要在电脑上操作？&quot;">​</a></h3><p>关于 OpenClaw 的基础安装配置，可以参考得到 AI 学习圈相关视频教程，安装成功后后再配置 Get 笔记 Skill</p><p><img src="`+r+'" alt=""></p><h3 id="_2-是否需要会员才能使用" tabindex="-1">2. 是否需要会员才能使用 <a class="header-anchor" href="#_2-是否需要会员才能使用" aria-label="Permalink to &quot;2. 是否需要会员才能使用&quot;">​</a></h3><p>多用户询问是否必须是 Get 笔记会员才能安装/使用 Skill。</p><p>是的，Get 笔记 Skill 安装后，调用相关能力仅限会员身份的账户使用</p><h3 id="_3-skill-能读取录音卡内容吗" tabindex="-1">3. Skill 能读取录音卡内容吗？ <a class="header-anchor" href="#_3-skill-能读取录音卡内容吗" aria-label="Permalink to &quot;3. Skill 能读取录音卡内容吗？&quot;">​</a></h3><p>可以读取包含录音卡录音笔记在内的所有笔记内容，也可以理解为您在 App 上看到的所有笔记，都可以读取</p><h3 id="_4-skill-能管理知识库吗" tabindex="-1">4. Skill 能管理知识库吗？ <a class="header-anchor" href="#_4-skill-能管理知识库吗" aria-label="Permalink to &quot;4. Skill 能管理知识库吗？&quot;">​</a></h3><p>想用 Skill 自动整理笔记进知识库，而不是手动操作。</p><p>可以通过该 Skill 完成知识库创建，笔记加入或移除等知识库相关的操作，可以试试： 把 XX 链接帮我保存到 XX 知识库</p><h3 id="_5-能安装到easyclaw-kimi-claw-上吗" tabindex="-1">5. 能安装到EasyClaw / Kimi Claw 上吗？ <a class="header-anchor" href="#_5-能安装到easyclaw-kimi-claw-上吗" aria-label="Permalink to &quot;5. 能安装到EasyClaw / Kimi Claw 上吗？&quot;">​</a></h3><p>询问 Skill 是否支持第三方 AI 平台部署。</p><p>理论上 OpenClaw 衍生的相关云服务都是支持的</p><h3 id="_6-能否一个-openclaw-对接两个账号" tabindex="-1">6. 能否一个 OpenClaw 对接两个账号？ <a class="header-anchor" href="#_6-能否一个-openclaw-对接两个账号" aria-label="Permalink to &quot;6. 能否一个 OpenClaw 对接两个账号？&quot;">​</a></h3><p>不建议这么做，因为两个账号之间的安全隔离比较难做，如果真的有需求，也建议创建不同的 Agent，并在不同的 Agent 内配置不同的Get 笔记 Skill 对应 API Key 等</p><h3 id="_8-没有看到官方技能包入口" tabindex="-1">8. 没有看到官方技能包入口 <a class="header-anchor" href="#_8-没有看到官方技能包入口" aria-label="Permalink to &quot;8. 没有看到官方技能包入口&quot;">​</a></h3><p>在 Get 笔记 App 内找不到官方 Skill 的安装入口。</p><p>可以使用以下任意一个方式安装</p><ul><li>请安装 Get笔记 技能，技能地址：<a href="https://clawhub.ai/iswalle/getnote" target="_blank" rel="noreferrer">https://clawhub.ai/iswalle/getnote</a></li><li>帮我安装 Get笔记 skill，地址是 <a href="./https%3A%2F%2Fraw.githubusercontent.com%2Fiswalle%2Fgetnote-openclaw%2Fmain%2FSKILL.html">https://raw.githubusercontent.com/iswalle/getnote-openclaw/main/SKILL.md</a></li></ul><h3 id="_9-api-key-安全性" tabindex="-1">9. API Key 安全性 <a class="header-anchor" href="#_9-api-key-安全性" aria-label="Permalink to &quot;9. API Key 安全性&quot;">​</a></h3><p>关心 API Key 是否安全，是否会被泄露。</p><p>API Key 只会在生成时显示一次，请妥善保管，建议写入小龙虾配置文件内，并不要提交到公开的代码仓库，也不要和朋友共享</p><p>如果怀疑泄露，请立即登录管理后台，点击“作废”：<a href="https://www.biji.com/openapi" target="_blank" rel="noreferrer">https://www.biji.com/openapi</a></p><h3 id="_10-skill-能精准读取所有笔记数据吗" tabindex="-1">10. Skill 能精准读取所有笔记数据吗？ <a class="header-anchor" href="#_10-skill-能精准读取所有笔记数据吗" aria-label="Permalink to &quot;10. Skill 能精准读取所有笔记数据吗？&quot;">​</a></h3><p>希望 Skill 能精准读出全部写入数据，而不只是作为上下文总结。</p><p>可以读取包含录音卡录音笔记在内的所有笔记内容，也可以读取录音笔记、链接笔记的原始内容，可以试试：</p><p>帮我查看一下 XX 笔记的原始内容是什么</p><h3 id="_11-skill-可以看视频总结功能吗" tabindex="-1">11. Skill 可以看视频总结功能吗？ <a class="header-anchor" href="#_11-skill-可以看视频总结功能吗" aria-label="Permalink to &quot;11. Skill 可以看视频总结功能吗？&quot;">​</a></h3><p>想知道 Skill 是否能访问 Get 笔记里的视频总结内容。</p><p>可以的，能够读取所有类型笔记的内容总结，包括上传的音视频生成的笔记</p><h3 id="_12-龙虾上线了-get笔记-skill-是官方的吗" tabindex="-1">12. 龙虾上线了 Get笔记 Skill，是官方的吗？ <a class="header-anchor" href="#_12-龙虾上线了-get笔记-skill-是官方的吗" aria-label="Permalink to &quot;12. 龙虾上线了 Get笔记 Skill，是官方的吗？&quot;">​</a></h3><p>上线消息引发用户确认是否为官方 Skill，并询问是否有专属群。</p><p>是的，目前官方发布的 Skill 和 MCP 相关地址如下：</p><ul><li><a href="https://clawhub.ai/iswalle/getnote" target="_blank" rel="noreferrer">https://clawhub.ai/iswalle/getnote</a></li><li><a href="https://github.com/iswalle/getnote-openclaw" target="_blank" rel="noreferrer">https://github.com/iswalle/getnote-openclaw</a></li><li><a href="https://github.com/iswalle/getnote-mcp" target="_blank" rel="noreferrer">https://github.com/iswalle/getnote-mcp</a></li></ul>',56)])])}const g=e(n,[["render",p]]);export{u as __pageData,g as default};
